mapper.select:
SELECT student_id AS studentId,
       check_date AS checkDate,
       checked_in AS checkedIn,
       check_time AS checkTime
FROM student_check_in_record
WHERE check_date BETWEEN #{beginDate} AND #{endDate}

    AND student_id = #{studentId}

ORDER BY check_date DESC, student_id ASC
LIMIT #{pageSize}
OFFSET #{offset}

SELECT COUNT(*)
FROM student_check_in_record
WHERE check_date BETWEEN #{beginDate} AND #{endDate}

    AND student_id = #{studentId}

SELECT s.checked_in FROM student_check_in_record AS s
WHERE student_id = #{studentId}
AND check_date = #{checkDate}
